This is the most complex example using React context for compound state management:

```typescript
// 1. Define Context Type
type CarouselContextProps = {
  carouselRef: ReturnType<typeof useEmblaCarousel>[0]
  api: ReturnType<typeof useEmblaCarousel>[1]
  scrollPrev: () => void
  scrollNext: () => void
  canScrollPrev: boolean
  canScrollNext: boolean
} & CarouselProps

// 2. Create Context
const CarouselContext = React.createContext<CarouselContextProps | null>(null)

// 3. Create Custom Hook for Context
function useCarousel() {
  const context = React.useContext(CarouselContext)
  if (!context) {
    throw new Error("useCarousel must be used within a <Carousel />")
  }
  return context
}

// 4. Root Component provides context
function Carousel({
  orientation = "horizontal",
  opts,
  setApi,
  plugins,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & CarouselProps) {
  const [carouselRef, api] = useEmblaCarousel(...)
  const [canScrollPrev, setCanScrollPrev] = React.useState(false)
  const [canScrollNext, setCanScrollNext] = React.useState(false)

  // Setup callbacks and effects...

  return (
    <CarouselContext.Provider value={{ carouselRef, api, opts, orientation, scrollPrev, scrollNext, canScrollPrev, canScrollNext }}>
      <div {...props}>
        {children}
      </div>
    </CarouselContext.Provider>
  )
}

// 5. Sub-components consume context
function CarouselContent({ className, ...props }: React.ComponentProps<"div">) {
  const { carouselRef, orientation } = useCarousel()
  return (...)
}

function CarouselPrevious({...}: React.ComponentProps<typeof Button>) {
  const { orientation, scrollPrev, canScrollPrev } = useCarousel()
  return (...)
}

// 6. Named Exports
export { type CarouselApi, Carousel, CarouselContent, CarouselItem, CarouselPrevious, CarouselNext }
```

**Key Pattern Points:**
- Error boundary in hook (`useCarousel()` throws if not within provider)
- Keeps internal logic separate from presentation
- Sub-components use the custom hook instead of direct Context access

