"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"

// --- Types ---

type StepperContextValue = {
  value: string
  onValueChange: (value: string) => void
  orientation: "horizontal" | "vertical"
  steps: string[]
  registerStep: (value: string) => void
  unregisterStep: (value: string) => void
}

type StepperItemContextValue = {
  value: string
  isActive: boolean
  isCompleted: boolean
}

type StepperProps = {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: "horizontal" | "vertical"
}

type StepperItemProps = {
  value: string
}

type StepperPanelProps = {
  value: string
}

// --- Contexts ---

const StepperContext = React.createContext<StepperContextValue | null>(null)
const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

// --- Hooks ---

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// --- Stepper (Root) ---

function Stepper({
  value: valueProp,
  defaultValue = "",
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [uncontrolledValue, setUncontrolledValue] =
    React.useState(defaultValue)
  const isControlled = valueProp !== undefined
  const value = isControlled ? valueProp : uncontrolledValue

  const [steps, setSteps] = React.useState<string[]>([])

  const registerStep = React.useCallback((stepValue: string) => {
    setSteps((prev) =>
      prev.includes(stepValue) ? prev : [...prev, stepValue]
    )
  }, [])

  const unregisterStep = React.useCallback((stepValue: string) => {
    setSteps((prev) => prev.filter((s) => s !== stepValue))
  }, [])

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) setUncontrolledValue(newValue)
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{
        value,
        onValueChange: handleValueChange,
        orientation,
        steps,
        registerStep,
        unregisterStep,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("cn-stepper flex flex-col gap-4", className)}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// --- StepperItem ---

function StepperItem({
  value,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperItemProps) {
  const {
    value: activeValue,
    orientation,
    steps,
    registerStep,
    unregisterStep,
  } = useStepper()

  React.useLayoutEffect(() => {
    registerStep(value)
    return () => unregisterStep(value)
  }, [value, registerStep, unregisterStep])

  const myIndex = steps.indexOf(value)
  const activeIndex = steps.indexOf(activeValue)
  const isActive = value === activeValue
  const isCompleted = myIndex !== -1 && activeIndex !== -1 && myIndex < activeIndex

  return (
    <StepperItemContext.Provider value={{ value, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
        data-orientation={orientation}
        className={cn(
          "cn-stepper-item group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-row items-center"
            : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// --- StepperTrigger ---

function StepperTrigger({
  className,
  children,
  onClick,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { value, isActive, isCompleted } = useStepperItem()

  return (
    <button
      type="button"
      role="tab"
      aria-selected={isActive}
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      className={cn(
        "cn-stepper-trigger flex cursor-pointer items-center gap-2 rounded-md text-sm font-medium whitespace-nowrap transition-colors",
        "focus-visible:ring-ring/50 focus-visible:outline-1 focus-visible:outline-ring focus-visible:ring-[3px]",
        "disabled:pointer-events-none disabled:opacity-50",
        "data-[state=active]:text-foreground",
        "data-[state=inactive]:text-muted-foreground hover:data-[state=inactive]:text-foreground",
        "data-[state=completed]:text-muted-foreground hover:data-[state=completed]:text-foreground",
        className
      )}
      onClick={(e) => {
        onValueChange(value)
        onClick?.(e)
      }}
      {...props}
    >
      {children}
    </button>
  )
}

// --- StepperTitle ---

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn(
        "cn-stepper-title text-sm font-semibold leading-none",
        className
      )}
      {...props}
    />
  )
}

// --- StepperDescription ---

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-xs text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// --- StepperSeparator ---

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { isCompleted } = useStepperItem()

  return (
    <div
      role="separator"
      aria-hidden="true"
      data-slot="stepper-separator"
      data-state={isCompleted ? "completed" : "inactive"}
      data-orientation={orientation}
      className={cn(
        "cn-stepper-separator bg-border transition-colors",
        orientation === "horizontal"
          ? "h-px flex-1"
          : "ms-3 w-px self-stretch min-h-4",
        "data-[state=completed]:bg-primary",
        className
      )}
      {...props}
    />
  )
}

// --- StepperPanel ---

function StepperPanel({
  value,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperPanelProps) {
  const { value: activeValue } = useStepper()
  const isActive = value === activeValue

  return (
    <div
      role="tabpanel"
      data-slot="stepper-panel"
      data-state={isActive ? "active" : "inactive"}
      hidden={!isActive}
      className={cn("cn-stepper-panel", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
  useStepperItem,
}

