          : "ms-3 w-px self-stretch min-h-4",
        "data-[state=completed]:bg-primary",
        className
      )}
      {...props}
    />
  )
}

// --- StepperPanel ---

function StepperPanel({
  value,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperPanelProps) {
  const { value: activeValue } = useStepper()
  const isActive = value === activeValue

  return (
    <div
      role="tabpanel"
      data-slot="stepper-panel"
      data-state={isActive ? "active" : "inactive"}
      hidden={!isActive}
      className={cn("cn-stepper-panel", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
  useStepperItem,
}

